import{_ as a,o,c as i,ae as t}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"New Tool for Link Validation","description":"","frontmatter":{"title":"New Tool for Link Validation","slug":"new-tool-for-link-validation"},"headers":[],"relativePath":"account-hub/new-tool-for-link-validation.md","filePath":"account-hub/new-tool-for-link-validation.md"}'),n={name:"account-hub/new-tool-for-link-validation.md"};function r(l,e,s,h,c,d){return o(),i("div",null,[...e[0]||(e[0]=[t('<p>The Branch Dashboard now has a link testing tool built into it, so you can help make sure your links route your users to their expected destination every time.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Given all the different variables at play in a deep linking scenario, from click location (Safari, Instagram, Facebook, TikTok, etc.) to operating system, it’s difficult to know what an end-user will actually see when they click your deep link.</p><p>To help you navigate this, Branch is releasing a new <strong>Link Validator</strong> tool within the Dashboard. This tool helps you test the links you create, so you can feel confident about what your users will see when they click on your deep links.</p><h2 id="link-types" tabindex="-1">Link Types <a class="header-anchor" href="#link-types" aria-label="Permalink to &quot;Link Types&quot;">​</a></h2><p>Please note that the Link Validator only accepts the following link types:</p><ul><li><p>Branch <a href="./create-quick-links.html">Short Links</a> created within the Branch Dashboard.</p></li><li><p>Branch Links created using one of our link-generating APIs:</p><ul><li><a href="./quick-links-api.html">Short Links API</a></li><li><a href="./deep-linking-api.html">Deep Linking API</a></li></ul></li></ul><h2 id="link-validator" tabindex="-1">Link Validator <a class="header-anchor" href="#link-validator" aria-label="Permalink to &quot;Link Validator&quot;">​</a></h2><p>To find the Link Validator tool:</p><ol><li>Go to the <a href="https://dashboard.branch.io/quick-links/validator" target="_blank" rel="noreferrer">Branch Dashboard</a> and use the left-side navigation bar to click on <strong>LinkHub</strong>, which is in the <strong>Channels &amp; Links</strong> section.</li><li>Click <strong>Validator</strong> in the dropdown under <strong>LinkHub</strong>.</li></ol><h2 id="learn-more" tabindex="-1">Learn More <a class="header-anchor" href="#learn-more" aria-label="Permalink to &quot;Learn More&quot;">​</a></h2><p>To learn more about how to use the Link Validator tool, check out our <a href="./link-validator.html">guide</a>.</p>',12)])])}const p=a(n,[["render",r]]);export{u as __pageData,p as default};
